import { inject as inject3 } from "/@fs/D:/projects/fronted/.angular/cache/20.3.12/fronted/vite/deps/@angular_core.js?v=2d7b26d0";
var roleGuard = (route, state) => {
  const authService = inject3(AuthService);
  const router = inject3(Router10);
  if (!authService.isLoggedIn()) {
    return router.createUrlTree(["/login"]);
  }
  const userRole = authService.getRole();
  const excludedRoles = route.data?.["excludedRoles"];
  if (excludedRoles && excludedRoles.length > 0) {
    if (userRole && excludedRoles.includes(userRole)) {
      return router.createUrlTree(["/projects"]);
    }
    return true;
  }
  const expectedRole = route.data?.["expectedRole"];
  if (!expectedRole) {
    return true;
  }
  if (userRole === expectedRole.toLowerCase()) {
    return true;
  }
  return router.createUrlTree(["/projects"]);
};

